diff --git a/assertj-core/src/main/java/org/assertj/core/condition/VerboseCondition.java b/assertj-core/src/main/java/org/assertj/core/condition/VerboseCondition.java
index 5c25492..b524850 100644
--- a/assertj-core/src/main/java/org/assertj/core/condition/VerboseCondition.java
+++ b/assertj-core/src/main/java/org/assertj/core/condition/VerboseCondition.java
@@ -23,6 +23,7 @@ import java.util.function.Predicate;
 import org.assertj.core.annotation.Beta;
 import org.assertj.core.api.AbstractAssert;
 import org.assertj.core.api.Condition;
+import org.assertj.core.presentation.StandardRepresentation;

@@ -103,14 +103,29 @@ public final class VerboseCondition
   public static VerboseCondition verboseCondition(Predicate predicate, String description, Function objectUnderTestDescriptor) {
+    requireNonNull(objectUnderTestDescriptor, "...");
     return new VerboseCondition<>(predicate, description, objectUnderTestDescriptor);
   }

+  public static VerboseCondition verboseCondition(Predicate predicate, String description) {
+    return new VerboseCondition<>(predicate, description, null);
+  }
+
   private VerboseCondition(Predicate predicate, String description, Function objectUnderTestDescriptor) {
     super(predicate, description);
     this.description = description;
-    this.objectUnderTestDescriptor = requireNonNull(objectUnderTestDescriptor, "...");
+    this.objectUnderTestDescriptor = objectUnderTestDescriptor;
   }

@@ -128,7 +144,13 @@ 
   protected String buildVerboseDescription(T objectUnderTest, boolean matches) {
     StringBuilder sb = new StringBuilder("%s".formatted(description));
-    if (!matches) sb.append(objectUnderTestDescriptor.apply(objectUnderTest));
+    if (!matches) {
+      if (objectUnderTestDescriptor != null) {
+        sb.append(objectUnderTestDescriptor.apply(objectUnderTest));
+      } else {
+        sb.append(" but was: ").append(StandardRepresentation.STANDARD_REPRESENTATION.toStringOf(objectUnderTest));
+      }
+    }
     return sb.toString();
   }
